import{_ as e,o as r,c as d,a3 as l}from"./chunks/framework.oxq6d-og.js";const m=JSON.parse('{"title":"Thread seçimi","description":"","frontmatter":{},"headers":[],"relativePath":"nthread/thread-selection.md","filePath":"nthread/thread-selection.md"}'),i={name:"nthread/thread-selection.md"};function t(n,a,o,s,c,h){return r(),d("div",null,[...a[0]||(a[0]=[l('<h1 id="thread-secimi" tabindex="-1">Thread seçimi <a class="header-anchor" href="#thread-secimi" aria-label="Permalink to &quot;Thread seçimi&quot;">​</a></h1><p>NThread tek bir hedef thread&#39;i yakalar ve yaşam döngüsü boyunca onu sürer. Bu nedenle thread seçimi yalnızca performans tercihi değildir; kararlılık ve hedef uygulamanın davranışı için temel bir karardır.</p><h2 id="erisim-olusturma-secenekleri" tabindex="-1">Erişim oluşturma seçenekleri <a class="header-anchor" href="#erisim-olusturma-secenekleri" aria-label="Permalink to &quot;Erişim oluşturma seçenekleri&quot;">​</a></h2><p><code>createAccessor</code> üç kimlik biçimini destekler:</p><table tabindex="0"><thead><tr><th><code>idType</code></th><th><code>id</code> anlamı</th><th>Davranış</th></tr></thead><tbody><tr><td><code>thread</code></td><td>Thread ID</td><td>Belirtilen tek thread kullanılır.</td></tr><tr><td><code>process</code></td><td>Process ID</td><td>Süreçten bir thread seçilir.</td></tr><tr><td><code>processAllThreadIds</code></td><td>Process ID</td><td>Tüm aday thread&#39;ler başlatılmaya çalışılır; ilk başarıyla park edilen kazanır. Varsayılandır.</td></tr></tbody></table><p><code>processAllThreadIds</code>, adayları <code>NThreadRaceAccessor</code> ile yarışa sokar. Kazananın dışındaki adaylar abort edilir; accessor zincirinin tamamı ise her aday için ayrı ayrı değil, yalnızca bir kez kurulur. Bu, “thread bulma” aşamasında dayanıklılık sağlar, fakat hangi thread&#39;in kazandığını görünür kılmayı daha da önemli yapar.</p><h2 id="hangi-thread-lerden-kacınılmalı" tabindex="-1">Hangi thread&#39;lerden kaçınılmalı? <a class="header-anchor" href="#hangi-thread-lerden-kacınılmalı" aria-label="Permalink to &quot;Hangi thread&#39;lerden kaçınılmalı?&quot;">​</a></h2><ul><li>UI mesaj döngüsünü çalıştıran thread&#39;ler: kısa bir park bile kullanıcı arayüzünü dondurabilir.</li><li>Loader veya başlangıç thread&#39;leri: loader lock tutuluyor olabilir.</li><li>Uzun süre mutex/critical section tutan worker thread&#39;ler.</li><li>Kapanmak üzere olan veya sıkça <code>ExitThread</code> çağıran thread&#39;ler.</li><li>Hook&#39;un bellek accessor&#39;ını sürmekte olan thread: NHook, suspend sayacı çakışmasın diye bunu ayrıca askıya almaz.</li></ul><h2 id="pratik-yaklasım" tabindex="-1">Pratik yaklaşım <a class="header-anchor" href="#pratik-yaklasım" aria-label="Permalink to &quot;Pratik yaklaşım&quot;">​</a></h2><p>Önce <code>processAllThreadIds</code> ile kontrollü bir test sürecinde çalışan bir aday bulun. Sonra loglanan kazanan thread ID&#39;siyle davranışı gözlemleyin. Hedefin thread modeli biliniyorsa, üretim benzeri deneylerde <code>idType: &#39;thread&#39;</code> ile bilinçli bir thread seçmek daha açıklanabilir sonuç verir.</p><p>Thread seçimi her çağrıda değişmez: NThread başlatıldıktan sonra aynı thread park edilir ve çağrılar bunun üzerinden yürür. Thread ölürse accessor&#39;ı sağlıklı kabul etmeyin; yeni bir accessor oluşturun.</p>',11)])])}const u=e(i,[["render",t]]);export{m as __pageData,u as default};
